import React from "react";

import type {IImageComponent} from "@lmb-it/kitsconcerto-types";
import {ResponsiveElement, useSeparator} from "../../../../Factory";


const mapImageStylingProps = (props: IImageComponent) => {
    let resizeMode: undefined | 'cover'| 'contain' | 'stretch' | 'repeat' | 'center';

    if (props.objectFit) {
        resizeMode = props.objectFit;
    }else{
        resizeMode = undefined
    }

    return { resizeMode };
};
const Image = ({style, ref, src, ...props}: IImageComponent) => {
    const source = src ? { uri: src } : props.source;
    const stylingProps = mapImageStylingProps(props);
    const { cssProps, nativeProps } = useSeparator<Record<any, any>>(props);

    return (
        <ResponsiveElement
            nativeProps={{...nativeProps, ...stylingProps, source}}
            ref={ref}
            cssProps={cssProps}
            as={"Image"}
        />
    );
}

export default Image;
